# DESC: Cifra carpetas con seguridad de Grado Militar (AES-256 CTR) optimizado para archivos gigantes sin consumir RAM.
# ARGS: <Ruta_Carpeta> <Contraseña>
# RISK: high
# PERM: user
# MODE: external

import os
import sys
import sys
try:
    if sys.stdout is None or getattr(sys.stdout, 'name', '').upper() == 'NUL':
        sys.stdout = open('CONOUT$', 'w', encoding='utf-8')
        sys.stderr = open('CONOUT$', 'w', encoding='utf-8')
        sys.stdin = open('CONIN$', 'r', encoding='utf-8')
except Exception: pass

if hasattr(sys.stdout, 'reconfigure'):
    try: sys.stdout.reconfigure(encoding='utf-8')
    except Exception: pass
import shutil
import subprocess

try:
    from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
    from cryptography.hazmat.backends import default_backend
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
except ImportError:
    subprocess.check_call([sys.executable, "-m", "pip", "install", "cryptography", "--quiet"])
    from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
    from cryptography.hazmat.backends import default_backend
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC

if len(sys.argv) < 3:
    print("[X] Faltan parámetros. Usa: Cifrador_De_Carpetas.py <Ruta> <Contraseña>")
    sys.exit()

carpeta_objetivo = sys.argv[1]
password_raw = sys.argv[2]

if not os.path.isdir(carpeta_objetivo):
    print("[X] La ruta especificada no es una carpeta.")
    sys.exit()

print(f"[*] Sellando la carpeta: {carpeta_objetivo}")

# Paso 1: Empaquetar
print("[~] Empaquetando archivos... (Esto puede tardar dependiendo del tamaño)")
archivo_zip = shutil.make_archive(carpeta_objetivo, 'zip', carpeta_objetivo)

# Paso 2: Cifrar en Chunks (Evita límite de RAM y crasheos en archivos de +10GB)
salt = os.urandom(16)
nonce = os.urandom(16) # CTR mode requiere un Nonce único
kdf = PBKDF2HMAC(algorithm=hashes.SHA256(), length=32, salt=salt, iterations=600000)
key = kdf.derive(password_raw.encode()) # Se genera clave de 256 bits

cipher = Cipher(algorithms.AES(key), modes.CTR(nonce), backend=default_backend())
encryptor = cipher.encryptor()

import base64

# Img portadora (JPEG 1x1 diminuto)
CARRIER_B64 = b""

archivo_cifrado = carpeta_objetivo + " (Sello).png"
peso_total = os.path.getsize(archivo_zip)
chunck_size = 64 * 1024 # 64KB en memoria como máximo
bytes_procesados = 0
ultimo_porcentaje = -10

with open(archivo_zip, 'rb') as f_in, open(archivo_cifrado, 'wb') as f_out:
    # 1. Escribimos la imagen cebo para engañar al sistema (Portador)
    f_out.write(base64.b64decode(CARRIER_B64))
    
    # 2. Firma mágica para que el Descifrador sepa dónde empezar a leer
    f_out.write(b'---HORUS-VAULT---')
    
    # 3. Metadatos descifrado
    f_out.write(salt)
    f_out.write(nonce)
    
    while True:
        chunk = f_in.read(chunck_size)
        if len(chunk) == 0:
            break
            
        datos_cifrados = encryptor.update(chunk)
        f_out.write(datos_cifrados)
        bytes_procesados += len(chunk)
        
        # Actualizamos por consola sin saturar (cada 10%)
        if peso_total > 0:
            porcentaje_actual = int((bytes_procesados / peso_total) * 100)
            if porcentaje_actual >= ultimo_porcentaje + 10:
                print(f"[~] Sellando bloques encriptados... ({porcentaje_actual}%)")
                ultimo_porcentaje = porcentaje_actual
            
    f_out.write(encryptor.finalize())

print("\n[*] Borrando rastros de forma segura (Wipe)...")

# Paso 3: Borrado Seguro del ZIP y la Carpeta
os.remove(archivo_zip)

import stat

def force_writable(path):
    try:
        os.chmod(path, stat.S_IWRITE)
    except Exception:
        pass

def secure_delete_folder(root_path):
    chunk_sz = 1024 * 1024
    for root_dir, _, files in os.walk(root_path, topdown=False):
        for file in files:
            ruta = os.path.join(root_dir, file)
            try:
                force_writable(ruta)
                peso = os.path.getsize(ruta)
                with open(ruta, "r+b") as f:
                    b_escritos = 0
                    while b_escritos < peso:
                        bloque = min(chunk_sz, peso - b_escritos)
                        f.write(os.urandom(bloque))
                        b_escritos += bloque
                os.remove(ruta)
            except Exception:
                try:
                    os.remove(ruta)
                except Exception:
                    pass
    shutil.rmtree(root_path, ignore_errors=True)

secure_delete_folder(carpeta_objetivo)

print("\n[V] BÓVEDA SELLADA Y ASEGURADA EXITOSAMENTE.")
print("    Todos los rastros originales han sido destruidos mediante sobrescritura.")
sys.exit()
